 1→import { tool } from '@langchain/core/tools';
 2→import { interrupt } from '@langchain/langgraph';
 3→import { validateSpec, autoFixSpec } from '@json-render/core';
 4→import { z } from 'zod';
 5→import { EToolName } from '../../common/constant';
 6→
 7→interface Spec {
 8→  root: string;
 9→  elements: Record<string, unknown>;
10→  state?: Record<string, unknown>;
11→}
12→
13→function isValidSpecShape(value: unknown): value is Spec {
14→  return (
15→    !!value &&
16→    typeof value === 'object' &&
17→    typeof (value as Record<string, unknown>).root === 'string' &&
18→    typeof (value as Record<string, unknown>).elements === 'object'
19→  );
20→}
21→
22→export const renderUITool = tool(
23→  async (input) => {
24→    if (!input.title?.trim()) {
25→      throw new Error('render-ui 缺少 title');
26→    }
27→    if (!isValidSpecShape(input.spec)) {
28→      throw new Error('render-ui 缺少有效的 spec（需包含 root 和 elements）');
29→    }
30→
31→    let spec = input.spec as Spec;
32→    const { valid } = validateSpec(spec as Parameters<typeof validateSpec>[0]);
33→    if (!valid) {
34→      spec = autoFixSpec(spec as Parameters<typeof autoFixSpec>[0]) as unknown as Spec;
35→    }
36→
37→    if (input.interactive) {
38→      const answer = interrupt({
39→        kind: 'generative-ui' as const,
40→        title: input.title,
41→        spec,
42→      });
43→      return [
44→        typeof answer === 'string' ? answer : JSON.stringify(answer),
45→        null,
46→      ] as const;
47→    }
48→
49→    return [
50→      `已通过 Generative UI 向用户展示「${input.title}」，用户已看到完整的富文本卡片。请勿再以文字或 markdown 重复相同内容，直接继续后续任务或结束回复。`,
51→      { title: input.title, spec },
52→    ] as const;
53→  },
54→  {
55→    name: EToolName.RenderUI,
56→    description:
57→      '渲染富 UI 组件。可用于展示信息（interactive=false）或收集用户输入（interactive=true）。' +
58→      '需提供符合 json-render spec 格式（flat-map: root + elements + state）的 UI 定义。' +
59→      '当 interactive=true 时，调用后暂停执行等待用户回复。',
60→    responseFormat: 'content_and_artifact',
61→    schema: z.object({
62→      title: z.string().describe('UI 卡片标题'),
63→      spec: z
64→        .record(z.string(), z.any())
65→        .describe('json-render spec 对象，flat-map 格式（root + elements + state）'),
66→      interactive: z
67→        .boolean()
68→        .optional()
69→        .default(false)
70→        .describe(
71→          '是否需要等待用户交互。false=纯展示，agent 继续执行；true=暂停等待用户回复',
72→        ),
73→    }),
74→  },
75→);
