559→  function handleSetGenerativeUIAnswer(event: ChatEvent): void {
560→    const data = event.data as Record<string, unknown> | undefined;
561→    const interruptId = typeof data?.interruptId === 'string' ? data.interruptId : undefined;
562→    const answer = data?.answer as string | Record<string, unknown> | undefined;
563→    if (!interruptId) return;
564→
565→    for (let i = state.messages.length - 1; i >= 0; i -= 1) {
566→      const msg = state.messages[i];
567→      if (msg.generativeUI?.interruptId === interruptId) {
568→        state.messages[i] = {
569→          ...msg,
570→          generativeUI: {
571→            ...msg.generativeUI,
572→            answer,
573→          } as GenerativeUIMessage,
574→        };
575→        break;
576→      }
577→    }
578→  }
