 1→import { BadRequestException } from '@nestjs/common';
 2→import { IResumePayload } from '../../common/generative-ui';
 3→import { ChatDto, ResumeDto } from './chat.dto';
 4→
 5→function isPlainObject(value: unknown): value is Record<string, unknown> {
 6→  return typeof value === 'object' && value !== null && !Array.isArray(value);
 7→}
 8→
 9→function isResumeObject(value: unknown): value is ResumeDto {
10→  return isPlainObject(value);
11→}
12→
13→function isResumeAnswer(value: unknown): value is string | Record<string, unknown> {
14→  return typeof value === 'string' || isPlainObject(value);
15→}
16→
17→export function normalizeResumePayload(dto: ChatDto): IResumePayload | undefined {
18→  const { resume, requirements } = dto;
19→
20→  if (isResumeObject(resume)) {
21→    if (resume.answer === undefined) {
22→      throw new BadRequestException('resume.answer 不能为空');
23→    }
24→    if (!isResumeAnswer(resume.answer)) {
25→      throw new BadRequestException('resume.answer 必须是字符串或对象');
26→    }
27→
28→    return {
29→      interruptId: resume.interruptId,
30→      answer: resume.answer,
31→    };
32→  }
33→
34→  if (resume === true || requirements !== undefined) {
35→    if (!isPlainObject(requirements)) {
36→      throw new BadRequestException('旧版 resume 请求必须提供 requirements 对象');
37→    }
38→
39→    return { answer: requirements };
40→  }
41→
42→  if (resume !== undefined) {
43→    throw new BadRequestException('resume 必须是对象；旧版协议请使用 resume: true + requirements');
44→  }
45→
46→  return undefined;
47→}
