49→export function normalizeSlashSkillMentions(text: string, skillNames: string[]) {
50→  if (!text.includes('/') || skillNames.length === 0) {
51→    return text;
52→  }
53→
54→  const knownSkills = new Set(skillNames);
55→  return text.replace(/(^|\s)\/([a-z0-9-]+)/gi, (match, prefix: string, skillName: string) => {
56→    if (!knownSkills.has(skillName)) {
57→      return match;
58→    }
59→    return `${prefix}$${skillName}`;
60→  });
61→}
