 18→const VFS_RELATIVE_PATH_PROMPT = `## Important: Use Relative Paths in Execute Tool
 19→
 20→The sandbox environment does NOT support absolute paths in shell commands.
 21→When using the \`execute\` tool, you MUST use **relative paths** (without leading \`/\`) for all file operations.
 22→
 23→For example:
 24→- CORRECT: \`execute(command="python -c \\"import json; f=open('large_tool_results/get_dashboard_by_uid:5'); data=json.load(f); print(data)\\\"")\`
 25→- WRONG: \`execute(command="python -c \\"import json; f=open('/large_tool_results/get_dashboard_by_uid:5'); data=json.load(f); print(data)\\\"")\`
 26→
 27→This applies to ALL file paths used inside execute commands, including paths to files in \`large_tool_results/\` and any other local files.
 28→Note: The filesystem tools (read_file, write_file, ls, etc.) still use absolute paths starting with \`/\` — this restriction only applies to the \`execute\` tool.`;
 29→
 30→/**
 31→ * Middleware that instructs the LLM to use relative paths in execute tool commands,
 32→ * because the VFS sandbox environment does not support absolute paths in shell execution.
 33→ */
 34→const vfsRelativePathMiddleware = createMiddleware({
 35→  name: 'VfsRelativePathMiddleware',
 36→  wrapModelCall: async (request, handler) => {
 37→    const additionalPrompt = new SystemMessage({ content: VFS_RELATIVE_PATH_PROMPT });
 38→    return handler({
 39→      ...request,
 40→      messages: [additionalPrompt, ...request.messages],
 41→    });
 42→  },
 43→});
 44→
 45→/**
 46→ * Middleware that catches "maximum context length" API errors from models
 47→ * that don't natively throw ContextOverflowError (e.g., DeepSeek).
 48→ *
 49→ * Without this, the deepagents summarization middleware's safety net
 50→ * (ContextOverflowError catch → emergency summarization) never triggers,
 51→ * causing unrecoverable 400 errors when token estimation undercounts.
 52→ */
 53→const contextOverflowBridgeMiddleware = createMiddleware({
 54→  name: 'ContextOverflowBridgeMiddleware',
 55→  wrapModelCall: async (request, handler) => {
 56→    try {
 57→      return await handler(request);
 58→    } catch (err: unknown) {
 59→      const message = err instanceof Error ? err.message : String(err);
 60→      if (message.includes('maximum context length')) {
 61→        throw ContextOverflowError.fromError(
 62→          err instanceof Error ? err : new Error(message),
 63→        );
 64→      }
 65→      throw err;
 66→    }
 67→  },
 68→});
